import { bridgeStore } from '@bridgeStore/index';

function init(): void {
  function addLoader(): void {
    const spinner = document.querySelector('.ytp-spinner');

    if (spinner) {
      const spinnerMessageInnerHTML = `Пожалуйста подождите...<br>${process.env.EXTENSION_TITLE} очень старается ускорить загрузку ❤️`;
      const spinnerMessage = document.querySelector('.ytp-spinner-message');

      // Check and update the spinner message innerHTML
      if (
        spinnerMessage instanceof HTMLElement &&
        spinnerMessage.innerHTML !== spinnerMessageInnerHTML
      ) {
        spinnerMessage.innerHTML = spinnerMessageInnerHTML;
        spinnerMessage.style.marginTop = '48px';
      }

      // Check and update the spinner message display style
      if (
        spinnerMessage instanceof HTMLElement &&
        spinnerMessage.style.display !== 'block'
      ) {
        spinnerMessage.style.display = 'block';
      }
    }
  }

  // Check the value of currentState from local storage and insert loader if connected
  function checkAndAddLoader(): void {
    const { currentState } = bridgeStore.getState();

    if (currentState === 'connected') {
      addLoader();
    }
  }

  // Check and insert loader every second as it can be removed by youtube
  setInterval(checkAndAddLoader, 1000);
}

// Initial call to start the process
init();
